# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

from flask import Flask, request, jsonify, make_response
import jwt
import datetime
from functools import wraps
import secrets

app = Flask(__name__)

SECRET_KEY = secrets.token_hex(16)
ALGORITHM = "HS256"

def create_jwt(user):
    to_encode = {
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30),
        'iat': datetime.datetime.utcnow(),
        'sub': user
    }

    jwt_encoded = jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)
    return jwt_encoded.decode('utf-8')

def authenticate(token=None):
    if not token:
        return None

    try:
        jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return True
    except:
        return False

@app.route('/login', methods=['POST'])
def login():
    auth = request.authorization
    if not auth or not auth.username or not auth.password:
        return make_response('Could not verify', 401, {'WWW-Authenticate': 'Basic realm="Login required!"'})

    user = authenticate(auth.password)
    if user is None:
        return make_response('Invalid username or password', 401, {'WWW-Authenticate': 'Basic realm="Login required!"'})

    token = create_jwt(auth.username)
    return jsonify({'token': token})

def requires_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.headers.get('x-jwt')
        if not authenticate(auth):
            return make_response('Access denied. Authorization required.', 401, {'WWW-Authenticate': 'Bearer realm="Require JWT token."'})
        return f(*args, **kwargs)
    return decorated

@app.route('/api', methods=['GET'])
@requires_auth
def api():
    response = {'status': 'success'}
    return jsonify(response)

if __name__ == '__main__':
    app.run(debug=True)